CREATE TABLE public.exercise_facts (
  exercise_id        text PRIMARY KEY,
  is_bodyweight_lift boolean NOT NULL DEFAULT false,  -- equipment @> {bodyweight} AND category IN (compound,isolation)
  regions            text[]  NOT NULL DEFAULT '{}'    -- DISTINCT MUSCLES[m].region over ex.primary, subset of {push,pull,legs,core}
);
ALTER TABLE public.exercise_facts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.exercise_facts FORCE  ROW LEVEL SECURITY;
-- defense-in-depth: kill the public default-ACL auto-grant (authenticated=arwd) immediately, same migration
REVOKE ALL ON public.exercise_facts FROM anon, authenticated;
GRANT  SELECT ON public.exercise_facts TO authenticated;  -- catalogue is non-sensitive; anon gets nothing
CREATE POLICY exercise_facts_read ON public.exercise_facts FOR SELECT TO authenticated USING (true);
-- writes: postgres/service_role only (migration-seeded). No INSERT/UPDATE/DELETE policy exists => RLS+FORCE denies all client writes even if a stray grant reappears.
-- A single integer catalogue version lives in analytics.meta (see triggersFunctions); bumping it forces re-derive of all sessions.

CREATE TABLE public.analytics_profile (
  user_id        uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  unit           text NOT NULL DEFAULT 'lb' CHECK (unit IN ('lb','kg')),
  bodyweight     numeric(7,2),
  days_per_week  integer,
  updated_at     timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE public.analytics_profile ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.analytics_profile FORCE  ROW LEVEL SECURITY;
REVOKE ALL    ON public.analytics_profile FROM anon, authenticated;
GRANT  SELECT ON public.analytics_profile TO authenticated;
CREATE POLICY profile_read ON public.analytics_profile FOR SELECT TO authenticated USING ((select auth.uid()) = user_id);

CREATE SCHEMA IF NOT EXISTS analytics AUTHORIZATION postgres;
REVOKE ALL  ON SCHEMA analytics FROM PUBLIC;
-- explicitly ensure no client USAGE (anon/authenticated get nothing; do NOT grant USAGE to them ever)
GRANT USAGE ON SCHEMA analytics TO service_role;

CREATE TABLE analytics.meta (
  id smallint PRIMARY KEY DEFAULT 1 CHECK (id = 1),
  schema_version  integer NOT NULL DEFAULT 1,  -- bump on formula change OR exercise_facts reseed
  facts_version   integer NOT NULL DEFAULT 1
);
INSERT INTO analytics.meta (id) VALUES (1) ON CONFLICT DO NOTHING;

CREATE TABLE analytics.reconcile_queue (
  user_id     uuid PRIMARY KEY,
  enqueued_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE analytics.user_watermark (
  user_id            uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  last_blob_updated_at timestamptz,   -- SERVER updated_at of the blob last reconciled (monotonic, skew-proof)
  last_reconciled_at timestamptz,
  last_status        text,            -- ok | error | suspect_empty
  last_error         text,
  retry_count        integer NOT NULL DEFAULT 0
);
REVOKE ALL ON ALL TABLES IN SCHEMA analytics FROM anon, authenticated;

CREATE TYPE analytics.reconcile_result AS (sessions int, sets int, deleted int);

