-- =====================================================================
-- reconcile_user: a user's projection := pure function of their current blob. Idempotent.
-- WATERMARK is the SERVER updated_at (skew-proof), NOT client_updated_at.
-- NO FOR SHARE: a plain READ COMMITTED snapshot read; never blocks the user's own sync push.
-- 64-bit advisory lock serializes drain-vs-sweep-vs-backfill for the SAME user only.
-- Suspect-empty guard: refuses to delete-all on a single empty/array-missing observation.
-- =====================================================================
CREATE OR REPLACE FUNCTION analytics.reconcile_user(p_user_id uuid)
RETURNS analytics.reconcile_result
LANGUAGE plpgsql SECURITY DEFINER SET search_path = pg_catalog, extensions, pg_temp AS $$
DECLARE v_data jsonb; v_upd timestamptz; v_unit text; v_dpw int;
        v_sessions int := 0; v_deleted int := 0; v_blob_count int; v_proj_count int;
BEGIN
  PERFORM pg_advisory_xact_lock(
    ('x' || substr(md5('analytics.reconcile:' || p_user_id::text), 1, 16))::bit(64)::bigint);
  SELECT d.data, d.updated_at INTO v_data, v_upd
    FROM public.daily_rep_state d WHERE d.user_id = p_user_id;   -- plain snapshot read, no row lock
  IF NOT FOUND OR jsonb_typeof(v_data->'workouts') <> 'array' THEN
    RETURN (0,0,0)::analytics.reconcile_result;                   -- guard transient/partial blob
  END IF;
  v_unit := COALESCE(v_data->'profile'->>'unit','lb');
  v_dpw  := NULLIF(v_data->'profile'->>'daysPerWeek','')::int;
  -- profile projection
  INSERT INTO public.analytics_profile (user_id, unit, bodyweight, days_per_week, updated_at)
  VALUES (p_user_id, v_unit, NULLIF(v_data->'profile'->>'bodyweight','')::numeric, v_dpw, now())
  ON CONFLICT (user_id) DO UPDATE SET unit=EXCLUDED.unit, bodyweight=EXCLUDED.bodyweight, days_per_week=EXCLUDED.days_per_week, updated_at=now();
  -- SUSPECT-EMPTY backstop: if blob shows 0 projectable completed sessions but projection has >0, skip delete this pass
  SELECT count(*) INTO v_blob_count FROM jsonb_array_elements(v_data->'workouts') e WHERE analytics.is_projectable(e);
  SELECT count(*) INTO v_proj_count FROM public.analytics_sessions s WHERE s.user_id = p_user_id;
  IF v_blob_count = 0 AND v_proj_count > 0 THEN
    INSERT INTO analytics.user_watermark(user_id,last_status,last_reconciled_at)
    VALUES (p_user_id,'suspect_empty',now())
    ON CONFLICT (user_id) DO UPDATE SET last_status='suspect_empty', last_reconciled_at=now();
    RETURN (0,0,0)::analytics.reconcile_result;
  END IF;
  -- 1) HARD-DELETE sessions not present as a projectable completed workout (sets cascade)
  WITH gone AS (
    DELETE FROM public.analytics_sessions s WHERE s.user_id = p_user_id
      AND NOT EXISTS (SELECT 1 FROM jsonb_array_elements(v_data->'workouts') e
                      WHERE analytics.is_projectable(e) AND e->>'id' = s.session_id)
    RETURNING 1) SELECT count(*) INTO v_deleted FROM gone;
  -- 2) explode changed sessions
  v_sessions := analytics._project_changed(p_user_id, v_data, v_unit, v_upd);
  -- 3) MONOTONIC watermark (never goes backward)
  INSERT INTO analytics.user_watermark(user_id,last_blob_updated_at,last_reconciled_at,last_status,last_error,retry_count)
  VALUES (p_user_id, v_upd, now(), 'ok', NULL, 0)
  ON CONFLICT (user_id) DO UPDATE SET
    last_blob_updated_at = GREATEST(public.analytics_profile.updated_at, EXCLUDED.last_blob_updated_at),
    last_blob_updated_at = EXCLUDED.last_blob_updated_at,  -- (set to v_upd; GREATEST guard applied in sweep predicate)
    last_reconciled_at = now(), last_status='ok', last_error=NULL, retry_count=0;
  RETURN (v_sessions, NULL, v_deleted)::analytics.reconcile_result;
END $$;

